给你写一个简单的命令行计算器：

```python
#!/usr/bin/env python3
"""
简单计算器 - 支持加减乘除
"""

def add(x, y):
    return x + y

def subtract(x, y):
    return x - y

def multiply(x, y):
    return x * y

def divide(x, y):
    if y == 0:
        return "错误：不能除以零"
    return x / y

def main():
    print("🧮 简单计算器")
    print("支持运算: +  -  *  /")
    print("输入 'q' 退出\n")

    while True:
        try:
            expr = input(">>> ").strip()

            if expr.lower() == 'q':
                print("再见！")
                break

            # 支持两种输入方式：完整表达式或分步输入
            if ' ' in expr:
                # 格式: "5 + 3"
                parts = expr.split()
                if len(parts) != 3:
                    print("格式错误，请使用: 数字 运算符 数字")
                    continue

                num1, op, num2 = parts
                num1, num2 = float(num1), float(num2)
            else:
                # 直接 eval 计算（简单场景）
                print(f"= {eval(expr)}")
                continue

            # 执行运算
            if op == '+':
                result = add(num1, num2)
            elif op == '-':
                result = subtract(num1, num2)
            elif op == '*':
                result = multiply(num1, num2)
            elif op == '/':
                result = divide(num1, num2)
            else:
                print(f"不支持的操作符: {op}")
                continue

            # 整数结果去掉小数点
            if isinstance(result, float) and result.is_integer():
                result = int(result)
            print(f"= {result}")

        except ValueError:
            print("请输入有效的数字")
        except Exception as e:
            print(f"出错了: {e}")

if __name__ == "__main__":
    main()
```

**使用方法：**

```bash
python calculator.py
```

然后输入：
- `5 + 3` → 加法
- `10 - 4` → 减法
- `6 * 7` → 乘法
- `8 / 2` → 除法
- `q` → 退出

